findClosest = function (link, inid) {
	var result = link.closest(inid);
	if (result.length == 0) {
		result = link.find(inid);
		if (result.length == 0) {
			result = link.children(inid);
			if (result.length == 0) {
				result = $(inid);
			}
		}
	}
	return result.first();
};

