	function setMaxHeight(elm, child, offset = 32) {
		if (!elm || !elm.length) {
			return;
		}
		var target = elm;
		if (child) {
			target = elm.find(child);
			if (!target || !target.length) {
				return;
			}
		}
		var top = $(window).height() - elm.offset().top - offset - desktopOffset;
		top = Math.max(top, 400);
		target.css("height", top + "px");
	}

