	function copyTextToClipboard(elem, text, cb) {
		try {
			window.navigator.clipboard.writeText(text);
		} catch (err) {
			// console.warn("Failed to copy text: ", err);
			var rm = false;
			if (!isFormField(elem)) {
				elem = $("<textarea name='tocopy' />");
				elem.text(text);
				// if in a modal
				var modal = $(".modal").last();
				if (modal.length) {
					modal.append(elem);
				} else {
					$("body").append(elem);
				}
				rm = true;
			}
			elem.trigger("focus");
			elem.trigger("select");
			document.execCommand("copy");
			if (rm) {
				elem.remove();
			}
		} finally {
			if (cb) {
				cb();
			}
		}
	}

	function isFormField(el) {
		if (!el || !el.length) {
			return false;
		}
		const tag = el[0].tagName;
		return tag === "INPUT" || tag === "TEXTAREA" || tag === "SELECT";
	}

	lQuery(".copytoclipboard").livequery("click", function (e) {
		e.preventDefault();
		e.stopPropagation();
		var btn = $(this);
		var textElement = null;
		var textToCopy = btn.data("text");
		var mime = btn.data("mime") || "text/plain";

		if (!textToCopy) {
			var selectid = btn.data("textsource");
			textElement = $("#" + selectid);
			if (mime && mime.endsWith("/html")) {
				textToCopy = textElement.html();
			} else if (isFormField(textElement)) {
				textToCopy = textElement.val();
			} else {
				textToCopy = textElement.text();
			}
		}
		if (!textToCopy) {
			var copyTextTarget = btn.data("copytarget");
			if (copyTextTarget) {
				textElement = $("#" + copyTextTarget);
				if (mime && mime.endsWith("/html")) {
					textToCopy = textElement.html();
				} else if (isFormField(textElement)) {
					textToCopy = textElement.val();
				} else {
					textToCopy = textElement.text();
				}
			}
		}

		if (!textToCopy) {
			return;
		}

		copyTextToClipboard(textElement, textToCopy, function () {
			customToast("Copied to clipboard!");
			var btnHtm = btn.html();
			var _btnHtm = btnHtm;
			btnHtm = btnHtm.replace("bi-copy", "bi-check-lg");
			btnHtm = btnHtm.replace("fa-copy", "fas fa-check");
			btnHtm = btnHtm.replace("Copy", "Copied");
			btn.html(btnHtm);
			setTimeout(() => {
				btn.html(_btnHtm);
			}, 2500);
		});
	});

	lQuery(".downloadtext").livequery("click", function (e) {
		var selectid = $(this).data("textsource");
		var textElement = $("#" + selectid);
		var mime = $(this).data("mime") || "text/plain";

		var textToDownload = null;
		if (mime.endsWith("/html")) {
			textToDownload = textElement.html();
		} else if (isFormField(textElement)) {
			textToDownload = textElement.val();
		} else {
			textToDownload = textElement.text();
		}
		if (!textToDownload) {
			return;
		}

		var ext = $(this).data("ext") || "txt";
		const blob = new Blob([textToDownload], { type: mime });
		const url = URL.createObjectURL(blob);
		const a = document.createElement("a");
		a.href = url;
		a.download = selectid + "." + ext;
		document.body.appendChild(a);
		a.click();
		document.body.removeChild(a);
		URL.revokeObjectURL(url);
	});

	lQuery(".copyFromTarget").livequery("click", function (e) {
		e.preventDefault();
		if ("clipboard" in navigator) {
			var $this = $(this);
			var type = $this.data("type") || "text";
			var btnText = $this.text();
			var target = $this.data("target");
			if (!target) return;
			var targetEl = $("#" + target);
			if (type == "text") {
				var data = targetEl.text();
				if (targetEl.is("input") || targetEl.is("textarea")) {
					data = targetEl.val();
				}
				navigator.clipboard.writeText(data);
				$this.html('<i class="bi bi-check-lg me-1"></i> Copied!');
				setTimeout(() => {
					$this.html('<i class="bi bi-clipboard me-1"></i> ' + btnText);
				}, 2000);
			} else {
				if (!targetEl.is("img")) {
					targetEl = targetEl.find("img");
				}
				var dataURL = targetEl.attr("src");
				if (!dataURL) {
					return;
				}
				$this.html('<i class="fas fa-spinner fa-spin"></i>');
				fetch(dataURL)
					.then((res) => res.blob())
					.then((blob) => {
						navigator.clipboard.write([
							new ClipboardItem({
								"image/png": blob,
							}),
						]);
					})
					.then(() => {
						$this.html('<i class="bi bi-check-lg"></i> Copied!');
						setTimeout(() => {
							$this.html('<i class="bi bi-clipboard"></i> ' + btnText);
						}, 2000);
					})
					.catch(() => {
						$this.html('<i class="bi bi-clipboard"></i> ' + btnText);
					});
			}
		} else {
			alert("Clipboard API not supported, please use a modern browser.");
			return;
		}
	});

